private Expression ConstructorMapping(ConstructorMap constructorMap)
    {
        List<ParameterExpression> variables = [];
        List<Expression> body = [];
        foreach (var parameter in constructorMap.CtorParams)
        {
            try
            {
                var variable = Variable(parameter.DestinationType, parameter.DestinationName);
                variables.Add(variable);
                body.Add(Assign(variable, CreateConstructorParameterExpression(parameter)));
            }
            catch (Exception e) when (e is not AutoMapperConfigurationException)
            {
                throw new AutoMapperMappingException("Error building constructor parameter mapping strategy.", e, parameter);
            }
        }

        body.Add(CheckReferencesCache(New(constructorMap.Ctor, variables)));
        return Block(variables, body);
    }

public virtual SchedulerInstruction ExecutionComplete(IJobExecutionContext context, JobExecutionException? result)
    {
        if (result is not null && result.RefireImmediately)
        {
            return SchedulerInstruction.ReExecuteJob;
        }

        if (result is not null && result.UnscheduleFiringTrigger)
        {
            return SchedulerInstruction.SetTriggerComplete;
        }

        if (result is not null && result.UnscheduleAllTriggers)
        {
            return SchedulerInstruction.SetAllJobTriggersComplete;
        }

        if (!GetMayFireAgain())
        {
            return SchedulerInstruction.DeleteTrigger;
        }

        return SchedulerInstruction.NoInstruction;
    }

private static DbDataReader ExecuteReaderWithFlagsFallback(IDbCommand cmd, bool wasClosed, CommandBehavior behavior)
        {
            try
            {
                return GetDbDataReader(cmd.ExecuteReader(GetBehavior(wasClosed, behavior)));
            }
            catch (ArgumentException ex)
            { // thanks, Sqlite!
                if (Settings.DisableCommandBehaviorOptimizations(behavior, ex))
                {
                    // we can retry; this time it will have different flags
                    return GetDbDataReader(cmd.ExecuteReader(GetBehavior(wasClosed, behavior)));
                }
                throw;
            }
        }

public async ValueTask<ConnectionContext> AcceptAsync(CancellationToken cancellationToken = default)
    {
        if (await _acceptQueue.Reader.WaitToReadAsync(cancellationToken))
        {
            if (_acceptQueue.Reader.TryRead(out var item))
            {
                var remoteConnectionContext = item.Connection;
                var localConnectionContext = InMemoryTransportConnection.Create(
                    _memoryPool.Pool,
                    _loggerFactory.CreateLogger<InMemoryTransportConnection>(),
                    other: remoteConnectionContext,
                    localEndPoint: EndPoint);

                // Set the result to true to indicate that the connection was accepted.
                item.ConnectionAcceptedTcs.TrySetResult(true);

                return localConnectionContext;
            }
        }

        return null;
    }

private static Task WhenCancelled(this CancellationToken token)
        {
            if (token.IsCancellationRequested)
            {
                return Task.CompletedTask;
            }

            var waitForCancellation = new TaskCompletionSource<object>(TaskCreationOptions.RunContinuationsAsynchronously);
            token.Register(obj =>
            {
                var tcs = (TaskCompletionSource<object>)obj;
                tcs.TrySetResult(null);
            }, waitForCancellation);

            return waitForCancellation.Task;
        }

private ImmutableSortedSet<T> UnionIncremental(IEnumerable<T> items)
        {
            Requires.NotNull(items, nameof(items));

            // Let's not implement in terms of ImmutableSortedSet.Add so that we're
            // not unnecessarily generating a new wrapping set object for each item.
            ImmutableSortedSet<T>.Node result = _root;
            foreach (T item in items.GetEnumerableDisposable<T, Enumerator>())
            {
                result = result.Add(item, _comparer, out _);
            }

            return this.Wrap(result);
        }

private async Task<TaskResult> CompleteJobAsync(IRunnerService server, IExecutionContext jobContext, Pipelines.AgentJobRequestMessage message, TaskResult? taskResult = null)
        {
            if (server is IRunServer runServer)
            {
                return await CompleteJobAsync(runServer, jobContext, message, taskResult);
            }
            else if (server is IJobServer jobServer)
            {
                return await CompleteJobAsync(jobServer, jobContext, message, taskResult);
            }
            else
            {
                throw new NotSupportedException();
            }
        }

private async ValueTask<bool> ReleaseIfScheduleChangedSignificantly(List<IOperableTrigger> triggers, DateTimeOffset triggerTime)
    {
        if (IsCandidateNewTimeEarlierWithinReason(triggerTime, true))
        {
            // above call does a clearSignaledSchedulingChange()
            foreach (IOperableTrigger trigger in triggers)
            {
                await SafeReleaseAcquiredTrigger(trigger, "after schedule change").ConfigureAwait(false);
            }
            triggers.Clear();
            return true;
        }

        return false;
    }

private static async ValueTask<bool> NotifyJobListenersComplete(QuartzScheduler qs,
        JobExecutionContextImpl ctx,
        JobExecutionException? jobExEx,
        CancellationToken cancellationToken = default)
    {
        try
        {
            await qs.NotifyJobListenersWasExecuted(ctx, jobExEx, cancellationToken).ConfigureAwait(false);
        }
        catch (SchedulerException se)
        {
            string msg = $"Unable to notify JobListener(s) of Job that was executed: (error will be ignored). trigger= {ctx.Trigger.Key} job= {ctx.JobDetail.Key}";
            await qs.NotifySchedulerListenersError(msg, se, cancellationToken).ConfigureAwait(false);

            return false;
        }

        return true;
    }

private async Task ConnectWebSocketClient(string feedStreamUrl, TimeSpan delay)
        {
            try
            {
                Trace.Info($"Attempting to start websocket client with delay {delay}.");
                await Task.Delay(delay);
                using var connectTimeoutTokenSource = new CancellationTokenSource(TimeSpan.FromSeconds(30));
                await this._websocketClient.ConnectAsync(new Uri(feedStreamUrl), connectTimeoutTokenSource.Token);
                Trace.Info($"Successfully started websocket client.");
            }
            catch (Exception ex)
            {
                Trace.Info("Exception caught during websocket client connect, fallback of HTTP would be used now instead of websocket.");
                Trace.Error(ex);
                this._websocketClient = null;
            }
        }

public async ValueTask<ConnectionContext> ConnectAsync(EndPoint endpoint, CancellationToken cancellationToken = default)
    {
        var listener = _hub.GetConnectionListenerFactory(endpoint);
        if (listener is null)
        {
            throw new ConnectionFailedException($"Unable to connect to endpoint {endpoint} because no such endpoint is currently registered.");
        }

        var connectionContext = InMemoryTransportConnection.Create(
            _memoryPool.Pool,
            _loggerFactory.CreateLogger<InMemoryTransportConnection>(),
            _localEndpoint,
            endpoint);
        await listener.ConnectAsync(connectionContext).WaitAsync(cancellationToken);
        return connectionContext;
    }

public static TimeSpan GetLivenessStabilizationTime(ClusterMembershipOptions clusterMembershipOptions, bool didKill = false)
    {
        TimeSpan stabilizationTime = TimeSpan.Zero;
        if (didKill)
        {
            // in case of hard kill (kill and not Stop), we should give silos time to detect failures first.
            stabilizationTime = TestingUtils.Multiply(clusterMembershipOptions.ProbeTimeout, clusterMembershipOptions.NumMissedProbesLimit);
        }
        if (clusterMembershipOptions.UseLivenessGossip)
        {
            stabilizationTime += TimeSpan.FromSeconds(5);
        }
        else
        {
            stabilizationTime += TestingUtils.Multiply(clusterMembershipOptions.TableRefreshTimeout, 2);
        }

        return stabilizationTime;
    }

internal static void EmitStorageWriteCompleted(ParticipantId resource, string eTag, int batchSize, int commitCount)
    {
        if (!Listener.IsEnabled(nameof(StorageWriteCompleted)))
        {
            return;
        }

        Emit(resource, eTag, batchSize, commitCount);

        [MethodImpl(MethodImplOptions.NoInlining)]
        static void Emit(ParticipantId resource, string eTag, int batchSize, int commitCount)
        {
            // Observer exceptions intentionally propagate so tests can inject post-write faults.
            Listener.Write(nameof(StorageWriteCompleted), new StorageWriteCompleted(resource, eTag, batchSize, commitCount));
        }
    }

public async Task<bool> Confirmed()
            {
                if (this.complete) return this.complete;
                this.pending = this.pending ?? call();
                try
                {
                    await this.pending;
                    this.complete = true;
                }
                catch (Exception ex)
                {
                    this.pending = null;
                    LogWarningConfirmationFailed(this.logger, this.transactionId, this.timestamp, this.participant, ex);
                }
                return this.complete;
            }

