public void ProcessFiles(IExecutionContext context, ContainerInfo container)
        {
            foreach (var fileCommand in _commandExtensions)
            {
                try
                {
                    fileCommand.ProcessCommand(context, Path.Combine(_fileCommandDirectory, fileCommand.FilePrefix + _fileSuffix), container);
                }
                catch (Exception ex)
                {
                    context.Error($"Unable to process file command '{fileCommand.ContextName}' successfully.");
                    context.Error(ex);
                    context.CommandResult = TaskResult.Failed;
                }
            }
        }

public void ProcessCommand(IExecutionContext context, string filePath, ContainerInfo container)
        {
            var pairs = new EnvFileKeyValuePairs(context, filePath);
            foreach (var pair in pairs)
            {
                if (context.DeferredOutputs != null)
                {
                    context.DeferredOutputs[pair.Key] = pair.Value;
                }
                else
                {
                    context.SetOutput(pair.Key, pair.Value, out var reference);
                }
                context.Debug($"Set output {pair.Key} = {pair.Value}");
            }
        }

private Expression CreateMapperFunc(Expression assignmentFunc)
    {
        var mapperFunc = assignmentFunc;
        var overMaxDepth = OverMaxDepth(_typeMap);
        if (overMaxDepth != null)
        {
            mapperFunc = Condition(overMaxDepth, _configuration.Default(DestinationType), mapperFunc);
        }

        return CheckReferencesCache(mapperFunc);
    }

    private Expression CheckReferencesCache(Expression valueBuilder)
    {
        if (!_typeMap.PreserveReferences)
        {
            return valueBuilder;
        }

        var getCachedDestination = Call(ContextParameter, GetDestinationMethod, _source, Constant(DestinationType));
        return Coalesce(ToType(getCachedDestination, DestinationType), valueBuilder);
    }

private void AppendException(Exception currentException, List<ExceptionRenderingFormat> renderFormats, StringBuilder builder, Exception? aggregateException = null)
        {
            int currentLength = builder.Length;
            foreach (ExceptionRenderingFormat renderingFormat in renderFormats)
            {
                int beforeRenderLength = builder.Length;
                var currentRenderFunction = _renderingfunctions[renderingFormat];

                currentRenderFunction(this, builder, currentException, aggregateException);

                if (builder.Length != beforeRenderLength)
                {
                    currentLength = builder.Length;
                    builder.Append(_separator);
                }
            }

            builder.Length = currentLength;
        }
